INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-01011', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列敘述是一位學生的認知模式：「思考型態不再侷限於具體事務或問題，開始可運用抽象的、邏 輯的思考方式去推理或判斷，並解決周遭的問題」，以Piaget的認知發展論而言，此學生的認知已 發展到那一期？', '["感覺動作期", "準備運思期", "形式運思期", "具體運思期"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01012', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '個體出現認知缺陷障礙的風險經常會隨著年齡增長而提升。酗酒、人類免疫缺陷病毒感染、腦部 創傷、帕金森氏症可能會造成失智；但老年憂鬱跟初期的阿茲海默症狀類似，可能會造成混淆。 當個體認知有缺損，其評量篩檢分數比正常老化還嚴重，但沒有阿茲海默症或其他失智症常見的 功能障礙與行為問題，稱之為「輕度認知障礙」。在最新版的「精神疾病診斷與統計手冊第五版」 中以那個說法來取代「輕度認知障礙」？', '["輕度思覺認知障礙症", "輕度神經認知障礙症", "輕度心智認知障礙症", "輕度精神認知障礙症"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01013', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '在家庭中，通過親密的情感交流，讓父母親的價值、理想和信仰，經由仿效、認同及內化的方式， 融入兒童的人格，並成為兒童的理想、價值和態度。以上敘述，比較傾向下列家庭的何種功能？', '["社會化功能", "提供情感及愛", "性的規範", "政治功能"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01014', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '離婚可視為家庭壓力與危機之一。當父母離婚時，兒童會經驗到一連串的壓力源。有關離婚對兒 童產生的影響與適應之敘述，下列何者錯誤？', '["兒童性別以及監護人性別的差異對於離婚後的調適結果不會產生影響", "父母離婚時，兒童的年齡會影響他們長期與短期的調適過程", "兒童發展任務相關研究指出，幼兒雖然在父母離婚的一年或一年半之間，調適情況會惡化，但 以長期（10年後）的發展情況來看，幼兒的情況反而比年齡稍長的兒童還要好", "孩子個人的人格特質與性格會影響孩子調適與因應父母離婚的過程"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01015', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '主張人類的行為來自對外在刺激進行解釋、分析、然後再據以反應的觀點，比較傾向下列那種說法？', '["結構功能論", "社會衝突論", "社會階層說", "符號互動論"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01016', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '從家庭系統看夫妻面對癌症與疾病的敘述，下列何者錯誤？', '["夫妻過去關係的歷史影響夫妻因應的方式", "疾病的診斷結果可能會使關係很好或原本就很幸福的夫妻更加親密", "疾病的診斷結果可能會增強原本關係不好的夫妻之間的敵意", "配偶以不討論疾病的方式是面對關係的最好因應"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01017', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '不同的理論認為親子之間的爭吵與衝突有功能性的理由。有關親子衝突的理論觀點敘述，下列何 者錯誤？', '["危機理論觀點認為生活中的轉變並不會引發壓力，因此應該視親子衝突為生命週期正常變化， 個人能力可因應的狀況", "社會生理（sociobiological）觀點認為透過家庭內部的衝突與不和，可以促進青少年對外發展， 尋求家庭以外的伴侶，建立自己的家庭", "心理學的觀點認為親子衝突可以讓青少年體會父母親的不完美，讓青少年可以從依賴父母的情 境獨立出來，進而催化青少年的個別化過程", "認知發展觀點認為親子衝突是青少年和父母親對於家庭規定、家庭事件和家庭規範等方面觀點 的差異"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01018', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關生態系統論中「中介系統（mesosystems）」的敘述，下列何者正確？', '["它是系統參與者直接或面對面接觸的層次", "兒童的父母親是中介系統的代表", "它用來說明各微視系統間的互動關係，是個人社會生活的場域網絡", "地方政府是中介系統的代表"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01019', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '結構中的成員可以自外界獲取能力、知識與報酬的敘述，比較符合系統理論的那一項特點？', '["輸入（input）", "轉化（conversion）", "產出（output）", "回饋（feedback）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01020', 'social-worker', 'social-worker-moex-110-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '生態論中說明個人行為須因應環境限制和要求，環境也須遷就其成員需要的現象，比較接近下列 何者？', '["棲地（habitat）", "交流（transaction）", "熵（entropy）", "壓力（stress）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:06+00:00", "source_pdf_sha1": "4f79dc27d401", "answer_pdf_sha1": "893e87c04698", "source_family": "moex-gov-tw", "moex": {"exam_code": "110030", "c": "105", "s": "0405", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "110", "exam_name": "110年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
